export type SaveStatus = 'saved' | 'saving' | 'dirty' | 'error';
export type RenderStatus = 'idle' | 'rendering' | 'done' | 'error';

export type ClipTab = 'effects' | 'timing' | 'position' | 'audio' | 'text';

export interface EditorPreferences {
  scaleWidth: number;
  activeClipTab: ClipTab;
  assetPanel: {
    showAll: boolean;
    showHidden: boolean;
    hidden: string[];
  };
}

const defaultPreferences: EditorPreferences = {
  scaleWidth: 160,
  activeClipTab: 'effects',
  assetPanel: {
    showAll: false,
    showHidden: false,
    hidden: [],
  },
};

export function shouldAcceptPolledData(
  editSeq: number,
  savedSeq: number,
  polledSig: string,
  lastSavedSig: string,
): boolean {
  if (savedSeq < editSeq) {
    return false;
  }

  return polledSig !== lastSavedSig;
}

export interface UseTimelineDataResult {
