const round = (value: number): number => Math.round(value * 100) / 100;

const effectIdForClip = (clipId: string): string => `effect-${clipId}`;

const getUniqueClipId = (clipId: string, usedIds: Set<string>): string => {
  let duplicateIndex = 1;
  let candidate = clipId;

  while (usedIds.has(candidate)) {
    candidate = `${clipId}-dup-${duplicateIndex}`;
    duplicateIndex += 1;
  }

  return candidate;
};

const getClipDurationSeconds = (clip: TimelineClip): number => {
  return getClipSourceDuration(clip) / (clip.speed ?? 1);
};

const getDefaultClipMeta = (clip: TimelineClip): ClipMeta => {
  return {
    asset: clip.asset,
    track: clip.track,
    clipType: clip.clipType,
    from: clip.from,
    to: clip.to,
    speed: clip.speed,
    hold: clip.hold,
    volume: clip.volume,
    x: clip.x,
    y: clip.y,
    width: clip.width,
    height: clip.height,
    cropTop: clip.cropTop,
    cropBottom: clip.cropBottom,
    cropLeft: clip.cropLeft,
    cropRight: clip.cropRight,
    opacity: clip.opacity,
    text: clip.text,
    entrance: clip.entrance,
    exit: clip.exit,
    continuous: clip.continuous,
    transition: clip.transition,
    effects: clip.effects,
  };
};

const resolveAssetUrl = (file: string): string => {
  if (/^https?:\/\//.test(file)) {
    return file;
  }

  const normalized = file.replace(/\\/g, '/').replace(/^\/+/, '');
  return `/${normalized}`;
};

const buildAssetMap = (registry: AssetRegistry): Record<string, string> => {
  return Object.fromEntries(
    Object.entries(registry.assets ?? {}).map(([assetId, entry]) => [assetId, entry.file]),
  );
};

export const resolveTimelineConfig = async (
  config: TimelineConfig,
  registry: AssetRegistry,
  urlResolver?: UrlResolver,
): Promise<ResolvedTimelineConfig> => {
  return resolveTimelineConfigShared(config, registry, urlResolver ?? resolveAssetUrl);
};

export const configToRows = (
  config: TimelineConfig,
): Pick<TimelineData, 'rows' | 'meta' | 'effects' | 'clipOrder'> => {
  const migratedConfig = migrateToFlatTracks(config);
  const clipOrder: ClipOrderMap = Object.fromEntries(
    (migratedConfig.tracks ?? []).map((track) => [track.id, []]),
  );
  const effects: Record<string, EditorTimelineEffect> = {};
  const meta: Record<string, ClipMeta> = {};
  const rowsByTrack = new Map<string, TimelineAction[]>();
  const usedClipIds = new Set<string>();

  for (const track of migratedConfig.tracks ?? []) {
    rowsByTrack.set(track.id, []);
  }

  for (const clip of migratedConfig.clips) {
    const clipId = getUniqueClipId(clip.id, usedClipIds);
    if (clipId !== clip.id) {
      console.warn(`[timeline] Duplicate clip id "${clip.id}" on track "${clip.track}" detected; using "${clipId}" in editor state.`);
    }
    usedClipIds.add(clipId);

    clipOrder[clip.track] ??= [];
    clipOrder[clip.track].push(clipId);
    effects[effectIdForClip(clipId)] = { id: effectIdForClip(clipId) };
    meta[clipId] = getDefaultClipMeta(clip);

    const action: TimelineAction = {
      id: clipId,
      start: clip.at,
      end: clip.at + getClipDurationSeconds(clip),
      effectId: effectIdForClip(clipId),
    };

    rowsByTrack.get(clip.track)?.push(action);
  }

  return {
    rows: (migratedConfig.tracks ?? []).map((track) => ({
      id: track.id,
      actions: rowsByTrack.get(track.id) ?? [],
    })),
    meta,
    effects,
    clipOrder,
  };
};

export const rowsToConfig = (
  rows: TimelineRow[],
  meta: Record<string, ClipMeta>,
  output: TimelineOutput,
  clipOrder: ClipOrderMap,
  tracks: TrackDefinition[],
  customEffects?: TimelineConfig['customEffects'],
): TimelineConfig => {
  const actionMap = new Map<string, TimelineAction>();
  const trackActionIds: Record<string, string[]> = Object.fromEntries(tracks.map((track) => [track.id, []]));

  for (const row of rows) {
    for (const action of row.actions) {
      if (action.id.startsWith('uploading-')) continue;
      const clipMeta = meta[action.id];
      if (!clipMeta) {
        continue;
      }

      actionMap.set(action.id, action);
      trackActionIds[row.id] ??= [];
      trackActionIds[row.id].push(action.id);
    }
  }

  const clips: TimelineClip[] = [];
  for (const track of tracks) {
    const baseOrder = (clipOrder[track.id] ?? []).filter((clipId) => actionMap.has(clipId));
    const appendedIds = (trackActionIds[track.id] ?? []).filter((clipId) => !baseOrder.includes(clipId));

    for (const clipId of [...baseOrder, ...appendedIds]) {
      const action = actionMap.get(clipId);
      const clipMeta = meta[clipId];
      if (!action || !clipMeta) {
        continue;
      }

      const nextClip: Partial<TimelineClip> = {
        id: clipId,
        at: round(action.start),
        track: track.id,
        clipType: clipMeta.clipType,
        asset: clipMeta.asset,
        from: clipMeta.from,
        to: clipMeta.to,
        speed: clipMeta.speed,
        hold: clipMeta.hold,
        volume: clipMeta.volume,
        x: clipMeta.x,
        y: clipMeta.y,
        width: clipMeta.width,
        height: clipMeta.height,
        cropTop: clipMeta.cropTop,
        cropBottom: clipMeta.cropBottom,
        cropLeft: clipMeta.cropLeft,
        cropRight: clipMeta.cropRight,

export type TimelineEffect = {
  fade_in?: number;
  fade_out?: number;
};

export type TrackKind = 'visual' | 'audio';
export type TrackFit = 'cover' | 'contain' | 'manual';
export type TrackBlendMode =
  | 'normal'
  | 'multiply'
  | 'screen'
  | 'overlay'
  | 'darken'
  | 'lighten'
  | 'soft-light'
  | 'hard-light';
export type ClipType = 'media' | 'hold' | 'text';

export type TrackDefinition = {
  id: string;
  kind: TrackKind;
  label: string;
  scale?: number;
  fit?: TrackFit;
  opacity?: number;
  blendMode?: TrackBlendMode;
};

export type ClipEntrance = {
  type: string;
  duration: number;
};

export type ClipExit = {
  type: string;
  duration: number;
};

export type ClipContinuous = {
  type: string;
  intensity?: number;
};

export type ClipTransition = {
  type: string;
  duration: number;
};

export type TextAlignment = 'left' | 'center' | 'right';

export type TextClipData = {
  content: string;
  fontFamily?: string;
  fontSize?: number;
  color?: string;
  align?: TextAlignment;
  bold?: boolean;
  italic?: boolean;
};

export type TimelineClip = {
  id: string;
  at: number;
  track: string;
  clipType?: ClipType;
  asset?: string;
  from?: number;
  to?: number;
  speed?: number;
  hold?: number;
  volume?: number;
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  cropTop?: number;
  cropBottom?: number;
  cropLeft?: number;
  cropRight?: number;
  opacity?: number;
  text?: TextClipData;
  entrance?: ClipEntrance;
  exit?: ClipExit;
  continuous?: ClipContinuous;
  transition?: ClipTransition;
  effects?: TimelineEffect[] | Record<string, number>;
};

export type TimelineOutput = {
  resolution: string;
  fps: number;
  file: string;
  background?: string | null;
  background_scale?: number | null;
};

export type CustomEffectEntry = {
  code: string;
  category?: 'entrance' | 'exit' | 'continuous';
};

export type TimelineConfig = {
  output: TimelineOutput;
  clips: TimelineClip[];
  tracks?: TrackDefinition[];
  customEffects?: Record<string, CustomEffectEntry>;
};

export type AssetRegistryEntry = {
  file: string;
  type?: string;
  duration?: number;
  resolution?: string;
  fps?: number;
  generationId?: string;
  variantId?: string;
};

export type AssetRegistry = {
  assets: Record<string, AssetRegistryEntry>;
};

export type ResolvedAssetRegistryEntry = AssetRegistryEntry & {
  src: string;
};

export type ResolvedTimelineClip = TimelineClip & {
  assetEntry?: ResolvedAssetRegistryEntry;
};

export type ResolvedTimelineConfig = {
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clips: ResolvedTimelineClip[];
